   479→// === SUPPORT CHARACTER TYPES (MirrorBuddy v2.0) ===
   480→
   481→/**
   482→ * Learning differences that the platform supports.
   483→ * Used for both student profiles and buddy matching.
   484→ */
   485→export type LearningDifference =
   486→  | 'dyslexia'
   487→  | 'dyscalculia'
   488→  | 'dysgraphia'
   489→  | 'adhd'
   490→  | 'autism'
   491→  | 'cerebralPalsy'
   492→  | 'visualImpairment'
   493→  | 'auditoryProcessing';
   494→
   495→/**
   496→ * Role of support characters in the Support Triangle.
   497→ */
   498→export type SupportRole = 'learning_coach' | 'peer_buddy';
   499→
   500→/**
   501→ * Gender option for support characters.
   502→ * Students can choose their preferred coach/buddy gender.
   503→ */
   504→export type CharacterGender = 'male' | 'female';
   505→
   506→/**
   507→ * Extended student profile with learning differences.
   508→ * Used by Mario/Noemi buddies to personalize their approach.
   509→ */
   510→export interface ExtendedStudentProfile extends StudentProfile {
   511→  learningDifferences: LearningDifference[];
   512→  preferredCoach?: 'melissa' | 'roberto' | 'chiara' | 'andrea' | 'favij';
   513→  preferredBuddy?: 'mario' | 'noemi' | 'enea' | 'bruno' | 'sofia';
   514→}
   515→
   516→/**
   517→ * Support Teacher (Melissa/Roberto) - Learning Coach role.
   518→ * Focus: develop autonomy and study method.
   519→ * Relationship: vertical (coach), but talks "alongside" not "from above".
   520→ */
   521→export interface SupportTeacher {
   522→  id: 'melissa' | 'roberto' | 'chiara' | 'andrea' | 'favij';
   523→  name: string;
   524→  gender: CharacterGender;
   525→  age: number;
   526→  personality: string;
   527→  role: 'learning_coach';
   528→  voice: MaestroVoice;
   529→  voiceInstructions: string;
   530→  systemPrompt: string;
   531→  greeting: string;
   532→  avatar: string;
   533→  color: string;
   534→}
   535→
   536→/**
   537→ * MirrorBuddy (Mario/Noemi) - Peer Support role.
   538→ * Focus: make student feel less alone.
   539→ * Relationship: horizontal (friend), speaks as peer.
   540→ *
   541→ * System prompt is dynamic based on student profile:
   542→ * - Age is always student.age + 1
   543→ * - Learning differences mirror the student's
   544→ */
   545→export interface BuddyProfile {
   546→  id: 'mario' | 'noemi' | 'enea' | 'bruno' | 'sofia';
   547→  name: string;
   548→  gender: CharacterGender;
   549→  ageOffset: number; // Always 1 (one year older)
   550→  personality: string;
   551→  role: 'peer_buddy';
   552→  voice: MaestroVoice;
   553→  voiceInstructions: string;
   554→  /**
   555→   * Dynamic system prompt generator.
   556→   * Takes student profile to personalize Mario/Maria's background.
   557→   */
   558→  getSystemPrompt: (student: ExtendedStudentProfile) => string;
   559→  /**
   560→   * Dynamic greeting generator.
   561→   */
   562→  getGreeting: (student: ExtendedStudentProfile) => string;
   563→  avatar: string;
   564→  color: string;
   565→}
   566→
   567→/**
   568→ * Union type for any support character (coach or buddy).
   569→ */
   570→export type SupportCharacter = SupportTeacher | BuddyProfile;
   571→
   572→/**
   573→ * Character type identifier for routing.
   574→ * Note: 'support_assistant' was removed in Issue #16 - coaches handle platform support directly.
   575→ */
   576→export type CharacterType = 'maestro' | 'coach' | 'buddy';
   577→
   578→// === PARENT DASHBOARD TYPES ===
   579→
   580→/**
   581→ * Observation category for what each Maestro observes.
   582→ * Maps to the Maestro's specialty and observation focus.
   583→ */
   584→export type ObservationCategory =
   585→  | 'logical_reasoning'       // Archimede
   586→  | 'creativity'              // Leonardo
   587→  | 'verbal_expression'       // Dante
   588→  | 'study_method'            // Montessori
   589→  | 'critical_thinking'       // Socrate
   590→  | 'artistic_sensitivity'    // Mozart
   591→  | 'scientific_curiosity'    // Darwin
   592→  | 'spatial_memory'          // Marco Polo
   593→  | 'historical_understanding' // Giulio Cesare
   594→  | 'mathematical_intuition'  // Pitagora
   595→  | 'linguistic_ability'      // Cicerone
   596→  | 'philosophical_depth'     // Aristotele
   597→  | 'physical_awareness'      // Ippocrate
   598→  | 'experimental_approach'   // Galileo
   599→  | 'environmental_awareness' // Plinio
   600→  | 'collaborative_spirit'    // Alessandro Magno
   601→  | 'narrative_skill';        // Omero
   602→
   603→/**
   604→ * Single observation from a Maestro about the student.
   605→ */
   606→export interface MaestroObservation {
