   608→  maestroId: string;
   609→  maestroName: string;
   610→  category: ObservationCategory;
   611→  observation: string;
   612→  isStrength: boolean; // true = punto di forza, false = area di crescita
   613→  confidence: number; // 0-1, how confident the Maestro is
   614→  createdAt: Date;
   615→  sessionId?: string;
   616→}
   617→
   618→/**
   619→ * Suggested strategy for the student.
   620→ */
   621→export interface LearningStrategy {
   622→  id: string;
   623→  title: string;
   624→  description: string;
   625→  suggestedBy: string[]; // Maestro IDs that suggested this
   626→  forAreas: ObservationCategory[];
   627→  priority: 'high' | 'medium' | 'low';
   628→}
   629→
   630→/**
   631→ * Learning style profile.
   632→ */
   633→export interface LearningStyleProfile {
   634→  preferredChannel: 'visual' | 'auditory' | 'kinesthetic' | 'reading_writing';
   635→  optimalSessionDuration: number; // minutes
   636→  preferredTimeOfDay: 'morning' | 'afternoon' | 'evening';
   637→  motivators: string[];
   638→  challengePreference: 'step_by_step' | 'big_picture' | 'mixed';
