   721→  currentConversationId: string | null;
   722→  // Sync state
   723→  lastSyncedAt: Date | null;
   724→  pendingSync: boolean;
   725→  // Actions
   726→  createConversation: (maestroId?: string) => Promise<string>;
   727→  addMessage: (conversationId: string, message: Omit<ChatMessage, 'id' | 'timestamp'>) => Promise<void>;
   728→  setCurrentConversation: (id: string | null) => void;
   729→  deleteConversation: (id: string) => Promise<void>;
   730→  clearConversations: () => void;
   731→  // Sync actions
   732→  syncToServer: () => Promise<void>;
   733→  loadFromServer: () => Promise<void>;
   734→}
   735→
   736→export const useConversationStore = create<ConversationState>()(
   737→  (set) => ({
   738→      conversations: [],
   739→      currentConversationId: null,
   740→      lastSyncedAt: null,
   741→      pendingSync: false,
   742→
   743→      createConversation: async (maestroId) => {
   744→        const tempId = crypto.randomUUID();
   745→        const conversation: Conversation = {
   746→          id: tempId,
   747→          title: 'New Conversation',
   748→          messages: [],
   749→          maestroId,
   750→          createdAt: new Date(),
   751→          updatedAt: new Date(),
   752→        };
   753→
   754→        // Optimistic update
   755→        set((state) => ({
   756→          conversations: [conversation, ...state.conversations],
   757→          currentConversationId: tempId,
   758→        }));
   759→
   760→        // Sync to server
   761→        try {
   762→          const response = await fetch('/api/conversations', {
   763→            method: 'POST',
   764→            headers: { 'Content-Type': 'application/json' },
   765→            body: JSON.stringify({ maestroId }),
   766→          });
   767→
   768→          if (response.ok) {
   769→            const serverConv = await response.json();
   770→            // Update with server ID
   771→            set((state) => ({
   772→              conversations: state.conversations.map((c) =>
   773→                c.id === tempId ? { ...c, id: serverConv.id } : c
   774→              ),
   775→              currentConversationId:
   776→                state.currentConversationId === tempId
   777→                  ? serverConv.id
   778→                  : state.currentConversationId,
   779→            }));
   780→            return serverConv.id;
   781→          }
   782→        } catch (error) {
   783→          logger.error('Failed to create conversation on server', { error: String(error) });
   784→        }
   785→
   786→        return tempId;
   787→      },
   788→
   789→      addMessage: async (conversationId, message) => {
   790→        const messageWithId = {
   791→          ...message,
   792→          id: crypto.randomUUID(),
   793→          timestamp: new Date(),
   794→        };
   795→
   796→        // Optimistic update
   797→        set((state) => ({
   798→          conversations: state.conversations.map((conv) =>
   799→            conv.id === conversationId
   800→              ? {
   801→                  ...conv,
   802→                  messages: [...conv.messages, messageWithId],
   803→                  updatedAt: new Date(),
   804→                  title:
   805→                    conv.messages.length === 0 && message.role === 'user'
   806→                      ? message.content.slice(0, 50)
   807→                      : conv.title,
   808→                }
   809→              : conv
   810→          ),
   811→          pendingSync: true,
   812→        }));
   813→
   814→        // Sync to server
   815→        try {
   816→          await fetch(`/api/conversations/${conversationId}/messages`, {
   817→            method: 'POST',
   818→            headers: { 'Content-Type': 'application/json' },
   819→            body: JSON.stringify({
   820→              role: message.role,
   821→              content: message.content,
   822→              toolCalls: (message as { toolCalls?: unknown }).toolCalls,
   823→            }),
   824→          });
   825→        } catch (error) {
   826→          logger.error('Failed to add message to server', { error: String(error) });
   827→        }
   828→      },
   829→
   830→      setCurrentConversation: (id) => set({ currentConversationId: id }),
   831→
   832→      deleteConversation: async (id) => {
   833→        // Optimistic update
   834→        set((state) => ({
   835→          conversations: state.conversations.filter((c) => c.id !== id),
   836→          currentConversationId:
   837→            state.currentConversationId === id
   838→              ? null
   839→              : state.currentConversationId,
   840→        }));
   841→
   842→        // Sync to server
   843→        try {
   844→          await fetch(`/api/conversations/${id}`, { method: 'DELETE' });
   845→        } catch (error) {
   846→          logger.error('Failed to delete conversation on server', { error: String(error) });
   847→        }
   848→      },
   849→
   850→      clearConversations: () =>
   851→        set({ conversations: [], currentConversationId: null }),
   852→
   853→      syncToServer: async () => {
   854→        // Conversations are synced immediately on each action
   855→        set({ lastSyncedAt: new Date(), pendingSync: false });
   856→      },
   857→
   858→      loadFromServer: async () => {
   859→        try {
   860→          const response = await fetch('/api/conversations?limit=50');
   861→          if (response.ok) {
   862→            const conversations = await response.json();
   863→            set({
   864→              conversations: conversations.map((c: {
   865→                id: string;
   866→                title: string;
   867→                maestroId: string;
   868→                createdAt: string;
   869→                updatedAt: string;
   870→                lastMessage?: string;
   871→              }) => ({
   872→                ...c,
   873→                messages: [], // Messages are loaded on-demand
   874→                createdAt: new Date(c.createdAt),
   875→                updatedAt: new Date(c.updatedAt),
   876→              })),
   877→              lastSyncedAt: new Date(),
   878→              pendingSync: false,
   879→            });
   880→          }
   881→        } catch (error) {
   882→          logger.error('Conversations load failed', { error: String(error) });
   883→        }
   884→      },
   885→    })
   886→);
   887→
   888→// === LEARNINGS STORE ===
   889→
   890→interface Learning {
   891→  id: string;
   892→  category: 'preference' | 'strength' | 'weakness' | 'interest' | 'style';
   893→  insight: string;
   894→  maestroId?: string;
   895→  subject?: string;
   896→  confidence: number;
   897→  occurrences: number;
   898→  createdAt: Date;
   899→  updatedAt: Date;
   900→}
   901→
   902→interface LearningsState {
   903→  learnings: Learning[];
   904→  lastSyncedAt: Date | null;
   905→  // Actions
   906→  addLearning: (learning: Omit<Learning, 'id' | 'occurrences' | 'createdAt' | 'updatedAt'>) => Promise<void>;
   907→  removeLearning: (id: string) => Promise<void>;
   908→  getLearningsByCategory: (category: Learning['category']) => Learning[];
   909→  // Sync
   910→  loadFromServer: () => Promise<void>;
   911→}
   912→
   913→export const useLearningsStore = create<LearningsState>()(
   914→  (set, get) => ({
   915→      learnings: [],
   916→      lastSyncedAt: null,
   917→
   918→      addLearning: async (learning) => {
   919→        try {
   920→          const response = await fetch('/api/learnings', {
   921→            method: 'POST',
   922→            headers: { 'Content-Type': 'application/json' },
   923→            body: JSON.stringify(learning),
   924→          });
   925→
   926→          if (response.ok) {
   927→            const serverLearning = await response.json();
   928→            set((state) => {
   929→              // Check if this was a reinforcement
   930→              if (serverLearning.reinforced) {
   931→                return {
   932→                  learnings: state.learnings.map((l) =>
   933→                    l.id === serverLearning.id
   934→                      ? { ...l, confidence: serverLearning.confidence, occurrences: serverLearning.occurrences }
   935→                      : l
   936→                  ),
   937→                };
   938→              }
   939→              // New learning
   940→              return {
   941→                learnings: [
   942→                  {
   943→                    ...serverLearning,
   944→                    createdAt: new Date(serverLearning.createdAt),
   945→                    updatedAt: new Date(serverLearning.updatedAt),
   946→                  },
   947→                  ...state.learnings,
   948→                ],
   949→              };
   950→            });
   951→          }
   952→        } catch (error) {
   953→          logger.error('Failed to add learning', { error: String(error) });
   954→        }
   955→      },
   956→
   957→      removeLearning: async (id) => {
   958→        set((state) => ({
   959→          learnings: state.learnings.filter((l) => l.id !== id),
   960→        }));
   961→
   962→        try {
   963→          await fetch(`/api/learnings?id=${id}`, { method: 'DELETE' });
   964→        } catch (error) {
   965→          logger.error('Failed to remove learning', { error: String(error) });
   966→        }
   967→      },
   968→
   969→      getLearningsByCategory: (category) => {
   970→        return get().learnings.filter((l) => l.category === category);
   971→      },
   972→
   973→      loadFromServer: async () => {
   974→        try {
   975→          const response = await fetch('/api/learnings');
   976→          if (response.ok) {
   977→            const learnings = await response.json();
   978→            set({
   979→              learnings: learnings.map((l: Learning & { createdAt: string; updatedAt: string }) => ({
   980→                ...l,
   981→                createdAt: new Date(l.createdAt),
   982→                updatedAt: new Date(l.updatedAt),
   983→              })),
   984→              lastSyncedAt: new Date(),
   985→            });
   986→          }
   987→        } catch (error) {
   988→          logger.error('Learnings load failed', { error: String(error) });
   989→        }
   990→      },
   991→    })
   992→);
   993→
   994→// === HTML SNIPPETS STORE ===
   995→
   996→export interface HTMLSnippet {
   997→  id: string;
   998→  title: string;
   999→  description?: string;
  1000→  code: string; // Full HTML content (single file with embedded CSS/JS)
  1001→  subject?: string;
  1002→  maestroId?: string;
  1003→  createdAt: Date;
  1004→  updatedAt: Date;
  1005→  tags: string[];
  1006→}
  1007→
  1008→interface HTMLSnippetsState {
  1009→  snippets: HTMLSnippet[];
  1010→  // Actions
  1011→  addSnippet: (snippet: Omit<HTMLSnippet, 'id' | 'createdAt' | 'updatedAt'>) => string;
  1012→  updateSnippet: (id: string, updates: Partial<HTMLSnippet>) => void;
  1013→  deleteSnippet: (id: string) => void;
  1014→  getSnippetsBySubject: (subject: string) => HTMLSnippet[];
  1015→  getSnippetsByMaestro: (maestroId: string) => HTMLSnippet[];
  1016→}
  1017→
  1018→export const useHTMLSnippetsStore = create<HTMLSnippetsState>()(
  1019→  (set, get) => ({
  1020→      snippets: [],
  1021→
  1022→      addSnippet: (snippet) => {
  1023→        const id = crypto.randomUUID();
  1024→        const now = new Date();
  1025→        set((state) => ({
  1026→          snippets: [
  1027→            {
  1028→              ...snippet,
  1029→              id,
  1030→              createdAt: now,
  1031→              updatedAt: now,
  1032→            },
  1033→            ...state.snippets,
  1034→          ],
  1035→        }));
  1036→        return id;
  1037→      },
  1038→
  1039→      updateSnippet: (id, updates) =>
  1040→        set((state) => ({
  1041→          snippets: state.snippets.map((s) =>
  1042→            s.id === id ? { ...s, ...updates, updatedAt: new Date() } : s
  1043→          ),
  1044→        })),
  1045→
  1046→      deleteSnippet: (id) =>
  1047→        set((state) => ({
  1048→          snippets: state.snippets.filter((s) => s.id !== id),
  1049→        })),
  1050→
  1051→      getSnippetsBySubject: (subject) => {
  1052→        return get().snippets.filter(
  1053→          (s) => s.subject?.toLowerCase() === subject.toLowerCase()
  1054→        );
  1055→      },
  1056→
  1057→      getSnippetsByMaestro: (maestroId) => {
  1058→        return get().snippets.filter((s) => s.maestroId === maestroId);
  1059→      },
  1060→    })
  1061→);
  1062→
  1063→// === SCHOOL CALENDAR STORE ===
  1064→
  1065→export interface SchoolEvent {
  1066→  id: string;
  1067→  title: string;
  1068→  subject: string; // maps to maestro subject
  1069→  type: 'test' | 'homework' | 'project' | 'lesson' | 'exam';
  1070→  date: Date;
  1071→  description?: string;
  1072→  priority: 'low' | 'medium' | 'high';
  1073→  completed: boolean;
  1074→  maestroSuggested?: string; // recommended maestro id
  1075→}
  1076→
  1077→interface CalendarState {
  1078→  events: SchoolEvent[];
  1079→  // Actions
  1080→  addEvent: (event: Omit<SchoolEvent, 'id' | 'completed'>) => void;
  1081→  updateEvent: (id: string, updates: Partial<SchoolEvent>) => void;
  1082→  deleteEvent: (id: string) => void;
  1083→  toggleCompleted: (id: string) => void;
  1084→  getUpcomingEvents: (days: number) => SchoolEvent[];
  1085→  getEventsBySubject: (subject: string) => SchoolEvent[];
  1086→  getSuggestedMaestri: () => Array<{ maestroId: string; reason: string; priority: 'high' | 'medium' | 'low' }>;
  1087→}
  1088→
  1089→// Subject to Maestro ID mapping
  1090→const SUBJECT_TO_MAESTRO: Record<string, string> = {
  1091→  mathematics: 'euclide-matematica',
  1092→  math: 'euclide-matematica',
  1093→  matematica: 'euclide-matematica',
  1094→  history: 'clio-storia',
  1095→  storia: 'clio-storia',
  1096→  italian: 'dante-italiano',
  1097→  italiano: 'dante-italiano',
  1098→  literature: 'dante-italiano',
  1099→  letteratura: 'dante-italiano',
  1100→  english: 'shakespeare-english',
  1101→  inglese: 'shakespeare-english',
  1102→  science: 'curie-scienze',
  1103→  scienze: 'curie-scienze',
  1104→  physics: 'einstein-fisica',
  1105→  fisica: 'einstein-fisica',
  1106→  chemistry: 'curie-scienze',
  1107→  chimica: 'curie-scienze',
  1108→  biology: 'darwin-biologia',
  1109→  biologia: 'darwin-biologia',
  1110→  art: 'leonardo-arte',
  1111→  arte: 'leonardo-arte',
  1112→  philosophy: 'socrate-filosofia',
  1113→  filosofia: 'socrate-filosofia',
  1114→  geography: 'colombo-geografia',
  1115→  geografia: 'colombo-geografia',
  1116→  music: 'mozart-musica',
  1117→  musica: 'mozart-musica',
  1118→  latin: 'cicerone-latino',
  1119→  latino: 'cicerone-latino',
  1120→  greek: 'aristotele-greco',
  1121→  greco: 'aristotele-greco',
  1122→};
  1123→
  1124→export const useCalendarStore = create<CalendarState>()(
  1125→  (set, get) => ({
  1126→      events: [],
  1127→
  1128→      addEvent: (event) =>
  1129→        set((state) => {
  1130→          const subjectLower = event.subject.toLowerCase();
  1131→          const maestroId = SUBJECT_TO_MAESTRO[subjectLower];
  1132→          return {
  1133→            events: [
  1134→              ...state.events,
  1135→              {
  1136→                ...event,
  1137→                id: crypto.randomUUID(),
  1138→                completed: false,
  1139→                maestroSuggested: maestroId,
  1140→              },
  1141→            ],
  1142→          };
  1143→        }),
  1144→
  1145→      updateEvent: (id, updates) =>
  1146→        set((state) => ({
  1147→          events: state.events.map((e) =>
  1148→            e.id === id ? { ...e, ...updates } : e
  1149→          ),
  1150→        })),
  1151→
  1152→      deleteEvent: (id) =>
  1153→        set((state) => ({
  1154→          events: state.events.filter((e) => e.id !== id),
  1155→        })),
  1156→
  1157→      toggleCompleted: (id) =>
  1158→        set((state) => ({
  1159→          events: state.events.map((e) =>
  1160→            e.id === id ? { ...e, completed: !e.completed } : e
  1161→          ),
  1162→        })),
  1163→
  1164→      getUpcomingEvents: (days) => {
  1165→        const now = new Date();
  1166→        const future = new Date(now.getTime() + days * 24 * 60 * 60 * 1000);
  1167→        return get()
  1168→          .events.filter(
  1169→            (e) => !e.completed && new Date(e.date) >= now && new Date(e.date) <= future
  1170→          )
  1171→          .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  1172→      },
  1173→
  1174→      getEventsBySubject: (subject) => {
  1175→        return get().events.filter(
  1176→          (e) => e.subject.toLowerCase() === subject.toLowerCase()
  1177→        );
  1178→      },
  1179→
  1180→      getSuggestedMaestri: () => {
  1181→        const upcoming = get().getUpcomingEvents(7);
  1182→        const suggestions: Map<string, { count: number; nearestDays: number; types: Set<string> }> = new Map();
  1183→
  1184→        const now = new Date();
  1185→        upcoming.forEach((event) => {
  1186→          const maestroId = event.maestroSuggested;
  1187→          if (!maestroId) return;
  1188→
  1189→          const daysUntil = Math.ceil(
  1190→            (new Date(event.date).getTime() - now.getTime()) / (24 * 60 * 60 * 1000)
  1191→          );
  1192→
  1193→          if (suggestions.has(maestroId)) {
  1194→            const existing = suggestions.get(maestroId)!;
  1195→            existing.count++;
  1196→            existing.nearestDays = Math.min(existing.nearestDays, daysUntil);
  1197→            existing.types.add(event.type);
  1198→          } else {
  1199→            suggestions.set(maestroId, {
  1200→              count: 1,
  1201→              nearestDays: daysUntil,
  1202→              types: new Set([event.type]),
  1203→            });
  1204→          }
  1205→        });
  1206→
  1207→        return Array.from(suggestions.entries())
  1208→          .map(([maestroId, data]) => {
  1209→            let priority: 'high' | 'medium' | 'low' = 'low';
  1210→            let reason = '';
  1211→
  1212→            if (data.nearestDays <= 1) {
  1213→              priority = 'high';
  1214→              reason = data.types.has('exam') || data.types.has('test')
  1215→                ? 'Test tomorrow - review now!'
  1216→                : 'Event tomorrow';
  1217→            } else if (data.nearestDays <= 3) {
  1218→              priority = 'high';
  1219→              reason = `${data.count} event${data.count > 1 ? 's' : ''} in ${data.nearestDays} days`;
  1220→            } else if (data.nearestDays <= 5) {
  1221→              priority = 'medium';
  1222→              reason = `Prepare for upcoming ${Array.from(data.types).join('/')}`;
  1223→            } else {
  1224→              priority = 'low';
  1225→              reason = `${data.count} event${data.count > 1 ? 's' : ''} this week`;
  1226→            }
  1227→
  1228→            return { maestroId, reason, priority };
  1229→          })
  1230→          .sort((a, b) => {
  1231→            const priorityOrder = { high: 0, medium: 1, low: 2 };
  1232→            return priorityOrder[a.priority] - priorityOrder[b.priority];
  1233→          });
  1234→      },
  1235→    })
  1236→);
  1237→
  1238→// === UI STORE ===
  1239→
  1240→interface UIState {
  1241→  sidebarOpen: boolean;
  1242→  settingsOpen: boolean;
  1243→  currentView: 'maestri' | 'chat' | 'voice' | 'quiz' | 'flashcards' | 'homework' | 'progress';
  1244→  // Focus Mode - fullscreen tool view
  1245→  focusMode: boolean;
  1246→  focusTool: ToolState | null;
  1247→  focusToolType: ToolType | null;
  1248→  focusMaestroId: string | null;
  1249→  focusInteractionMode: 'voice' | 'chat';
  1250→  // Actions
  1251→  toggleSidebar: () => void;
  1252→  setSidebarOpen: (open: boolean) => void;
  1253→  toggleSettings: () => void;
  1254→  setCurrentView: (view: UIState['currentView']) => void;
  1255→  // Focus Mode Actions
  1256→  enterFocusMode: (toolType: ToolType, maestroId?: string, interactionMode?: 'voice' | 'chat') => void;
  1257→  setFocusTool: (tool: ToolState | null) => void;
  1258→  exitFocusMode: () => void;
  1259→}
  1260→
  1261→export const useUIStore = create<UIState>((set) => ({
  1262→  sidebarOpen: true,
  1263→  settingsOpen: false,
  1264→  currentView: 'maestri',
  1265→  focusMode: false,
  1266→  focusTool: null,
  1267→  focusToolType: null,
  1268→  focusMaestroId: null,
  1269→  focusInteractionMode: 'chat',
  1270→  toggleSidebar: () => set((state) => ({ sidebarOpen: !state.sidebarOpen })),
  1271→  setSidebarOpen: (sidebarOpen) => set({ sidebarOpen }),
  1272→  toggleSettings: () => set((state) => ({ settingsOpen: !state.settingsOpen })),
  1273→  setCurrentView: (currentView) => set({ currentView }),
  1274→  enterFocusMode: (toolType, maestroId, interactionMode = 'chat') => set({
  1275→    focusMode: true,
  1276→    focusToolType: toolType,
  1277→    focusMaestroId: maestroId || null,
  1278→    focusInteractionMode: interactionMode,
  1279→    focusTool: null, // Will be set when tool is created
  1280→  }),
  1281→  setFocusTool: (tool) => set({ focusTool: tool }),
  1282→  exitFocusMode: () => set({
  1283→    focusMode: false,
  1284→    focusTool: null,
  1285→    focusToolType: null,
  1286→    focusMaestroId: null,
  1287→    focusInteractionMode: 'chat',
  1288→  }),
  1289→}));
  1290→
  1291→// === SYNC HOOK ===
  1292→
  1293→export async function initializeStores() {
  1294→  // Ensure user exists (creates cookie if needed)
  1295→  await fetch('/api/user');
  1296→
  1297→  // Load data from server
  1298→  await Promise.all([
  1299→    useSettingsStore.getState().loadFromServer(),
  1300→    useProgressStore.getState().loadFromServer(),
  1301→    useConversationStore.getState().loadFromServer(),
  1302→    useLearningsStore.getState().loadFromServer(),
  1303→  ]);
  1304→}
  1305→
  1306→export function setupAutoSync(intervalMs = 30000) {
  1307→  // Auto-sync every 30 seconds if there are pending changes
  1308→  return setInterval(async () => {
  1309→    const settings = useSettingsStore.getState();
  1310→    const progress = useProgressStore.getState();
  1311→
  1312→    if (settings.pendingSync) {
  1313→      await settings.syncToServer();
  1314→    }
  1315→    if (progress.pendingSync) {
  1316→      await progress.syncToServer();
  1317→    }
  1318→  }, intervalMs);
  1319→}
