    26→// FSRS-5 Parameters (optimized defaults)
    27→const FSRS_PARAMS = {
    28→  w: [0.4, 0.6, 2.4, 5.8, 4.93, 0.94, 0.86, 0.01, 1.49, 0.14, 0.94, 2.18, 0.05, 0.34, 1.26, 0.29, 2.61],
    29→  requestRetention: 0.9,
    30→  maximumInterval: 36500,
    31→};
    32→
    33→// Calculate next review using FSRS-5
    34→function fsrs5Schedule(card: Flashcard, rating: Rating): Partial<Flashcard> {
    35→  const ratingMap: Record<Rating, number> = { again: 1, hard: 2, good: 3, easy: 4 };
    36→  const r = ratingMap[rating];
    37→
    38→  let newState: CardState = card.state;
    39→  let newStability = card.stability;
    40→  let newDifficulty = card.difficulty;
    41→  let newReps = card.reps;
    42→  let newLapses = card.lapses;
    43→  let scheduledDays = 1;
    44→
    45→  if (card.state === 'new') {
    46→    // First review
    47→    newState = 'learning';
    48→    newStability = FSRS_PARAMS.w[r - 1];
    49→    newDifficulty = FSRS_PARAMS.w[4] - Math.exp(FSRS_PARAMS.w[5] * (r - 3)) + 1;
    50→    newDifficulty = Math.max(1, Math.min(10, newDifficulty));
    51→    newReps = 1;
    52→  } else if (rating === 'again') {
    53→    // Lapse
    54→    newState = 'relearning';
    55→    newLapses = card.lapses + 1;
    56→    newStability = Math.max(0.1, card.stability * FSRS_PARAMS.w[11]);
    57→  } else {
    58→    // Successful review
    59→    newState = 'review';
    60→    newReps = card.reps + 1;
    61→
    62→    // Update difficulty
    63→    const deltaDifficulty = -FSRS_PARAMS.w[6] * (r - 3);
    64→    newDifficulty = Math.max(1, Math.min(10, card.difficulty + deltaDifficulty));
    65→
    66→    // Update stability
    67→    const retrievability = Math.pow(1 + card.elapsedDays / (9 * card.stability), -1);
    68→    const stabilityIncrease = Math.exp(FSRS_PARAMS.w[8]) *
    69→      (11 - newDifficulty) *
    70→      Math.pow(card.stability, -FSRS_PARAMS.w[9]) *
    71→      (Math.exp((1 - retrievability) * FSRS_PARAMS.w[10]) - 1);
    72→
    73→    if (rating === 'hard') {
    74→      newStability = card.stability * (1 + stabilityIncrease * FSRS_PARAMS.w[15]);
    75→    } else if (rating === 'easy') {
    76→      newStability = card.stability * (1 + stabilityIncrease * FSRS_PARAMS.w[16]);
    77→    } else {
    78→      newStability = card.stability * (1 + stabilityIncrease);
    79→    }
    80→  }
    81→
    82→  // Calculate interval
    83→  const requestedRetention = FSRS_PARAMS.requestRetention;
    84→  scheduledDays = Math.round(
    85→    9 * newStability * (1 / requestedRetention - 1)
    86→  );
    87→  scheduledDays = Math.max(1, Math.min(scheduledDays, FSRS_PARAMS.maximumInterval));
    88→
    89→  return {
    90→    state: newState,
    91→    stability: newStability,
    92→    difficulty: newDifficulty,
    93→    reps: newReps,
    94→    lapses: newLapses,
    95→    scheduledDays,
    96→    elapsedDays: 0,
    97→    lastReview: new Date(),
    98→    nextReview: new Date(Date.now() + scheduledDays * 24 * 60 * 60 * 1000),
    99→  };
   100→}
