    50→// ============================================================================
    51→
    52→const DB_NAME = 'convergio-materials';
    53→const DB_VERSION = 1;
    54→
    55→let dbInstance: IDBPDatabase<MaterialsDB> | null = null;
    56→
    57→/**
    58→ * Get the IndexedDB database instance
    59→ * Creates the database if it doesn't exist
