    91→export async function saveMaterial(
    92→  file: Blob,
    93→  metadata: Omit<MaterialsDB['metadata']['value'], 'id' | 'createdAt' | 'updatedAt'>
    94→): Promise<string> {
    95→  const db = await getMaterialsDB();
