   107→    id,
   108→    blob: file,
   109→    thumbnail,
   110→    createdAt: now.getTime(),
   111→  });
   112→
   113→  // Save metadata
   114→  await db.put('metadata', {
   115→    ...metadata,
   116→    id,
   117→    createdAt: now,
   118→    updatedAt: now,
   119→  });
   120→
   121→  return id;
   122→}
   123→
   124→/**
   125→ * Get all materials with optional filtering
   126→ */
   127→export async function getMaterials(filter?: {
   128→  subject?: string;
   129→  format?: 'image' | 'pdf';
   130→  limit?: number;
   131→}): Promise<Array<MaterialsDB['metadata']['value']>> {
   132→  const db = await getMaterialsDB();
   133→  let results = await db.getAll('metadata');
   134→
   135→  // Apply filters
   136→  if (filter?.subject) {
   137→    results = results.filter((m) => m.subject === filter.subject);
   138→  }
   139→  if (filter?.format) {
   140→    results = results.filter((m) => m.format === filter.format);
   141→  }
   142→
   143→  // Sort by date descending (most recent first)
   144→  results.sort((a, b) => b.createdAt.getTime() - a.createdAt.getTime());
   145→
   146→  // Apply limit
   147→  if (filter?.limit) {
   148→    results = results.slice(0, filter.limit);
   149→  }
   150→
   151→  return results;
   152→}
   153→
   154→/**
   155→ * Get a material's file blob by ID
   156→ */
   157→export async function getMaterialFile(id: string): Promise<Blob | undefined> {
   158→  const db = await getMaterialsDB();
   159→  const file = await db.get('files', id);
   160→  return file?.blob;
