   172→/**
   173→ * Get material metadata by ID
   174→ */
   175→export async function getMaterialMetadata(
   176→  id: string
   177→): Promise<MaterialsDB['metadata']['value'] | undefined> {
   178→  const db = await getMaterialsDB();
   179→  return db.get('metadata', id);
   180→}
   181→
   182→/**
   183→ * Update material metadata (e.g., after subject detection)
   184→ */
   185→export async function updateMaterialMetadata(
   186→  id: string,
   187→  updates: Partial<Pick<MaterialsDB['metadata']['value'], 'subject' | 'maestroId' | 'pageCount'>>
   188→): Promise<void> {
   189→  const db = await getMaterialsDB();
   190→  const existing = await db.get('metadata', id);
   191→
   192→  if (!existing) {
   193→    throw new Error(`Material not found: ${id}`);
   194→  }
   195→
   196→  await db.put('metadata', {
   197→    ...existing,
   198→    ...updates,
   199→    updatedAt: new Date(),
   200→  });
   201→}
   202→
   203→/**
   204→ * Delete a material (both file and metadata)
   205→ */
   206→export async function deleteMaterial(id: string): Promise<void> {
   207→  const db = await getMaterialsDB();
   208→  await db.delete('files', id);
   209→  await db.delete('metadata', id);
   210→}
   211→
   212→/**
   213→ * Get materials by subject
   214→ */
   215→export async function getMaterialsBySubject(
   216→  subject: string
   217→): Promise<Array<MaterialsDB['metadata']['value']>> {
   218→  const db = await getMaterialsDB();
   219→  return db.getAllFromIndex('metadata', 'by-subject', subject);
   220→}
   221→
   222→/**
   223→ * Get materials by format (image or pdf)
   224→ */
   225→export async function getMaterialsByFormat(
   226→  format: 'image' | 'pdf'
   227→): Promise<Array<MaterialsDB['metadata']['value']>> {
   228→  const db = await getMaterialsDB();
   229→  return db.getAllFromIndex('metadata', 'by-format', format);
   230→}
   231→
   232→/**
   233→ * Get recent materials
   234→ */
   235→export async function getRecentMaterials(
   236→  limit: number = 10
   237→): Promise<Array<MaterialsDB['metadata']['value']>> {
   238→  return getMaterials({ limit });
   239→}
   240→
   241→// ============================================================================
   242→// CLEANUP OPERATIONS
   243→// ============================================================================
   244→
   245→/**
   246→ * Delete all materials
   247→ */
   248→export async function clearAllMaterials(): Promise<void> {
   249→  const db = await getMaterialsDB();
   250→  await db.clear('files');
   251→  await db.clear('metadata');
   252→}
   253→
   254→/**
   255→ * Get storage statistics
   256→ */
   257→export async function getMaterialsStats(): Promise<{
   258→  total: number;
   259→  images: number;
   260→  pdfs: number;
   261→  totalSize: number;
   262→  bySubject: Record<string, number>;
   263→}> {
   264→  const db = await getMaterialsDB();
   265→  const all = await db.getAll('metadata');
   266→
   267→  const stats = {
   268→    total: all.length,
   269→    images: 0,
   270→    pdfs: 0,
   271→    totalSize: 0,
   272→    bySubject: {} as Record<string, number>,
   273→  };
   274→
   275→  for (const material of all) {
   276→    if (material.format === 'image') {
   277→      stats.images++;
   278→    } else if (material.format === 'pdf') {
   279→      stats.pdfs++;
   280→    }
   281→
   282→    stats.totalSize += material.size;
   283→
   284→    if (material.subject) {
   285→      stats.bySubject[material.subject] = (stats.bySubject[material.subject] || 0) + 1;
   286→    }
   287→  }
   288→
   289→  return stats;
   290→}
   291→
   292→// ============================================================================
   293→// THUMBNAIL GENERATION
   294→// ============================================================================
   295→
   296→/**
   297→ * Generate a thumbnail for an image blob
   298→ */
   299→async function generateThumbnail(blob: Blob, maxSize = 200): Promise<Blob> {
   300→  // Server-side check
   301→  if (typeof window === 'undefined') {
   302→    return blob;
   303→  }
   304→
   305→  return new Promise((resolve) => {
   306→    const img = new Image();
   307→
   308→    img.onload = () => {
   309→      const canvas = document.createElement('canvas');
   310→      const scale = Math.min(maxSize / img.width, maxSize / img.height);
   311→      canvas.width = img.width * scale;
   312→      canvas.height = img.height * scale;
   313→
   314→      const ctx = canvas.getContext('2d');
   315→      if (!ctx) {
   316→        resolve(blob);
   317→        return;
   318→      }
   319→
   320→      ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
   321→
   322→      canvas.toBlob(
   323→        (thumbBlob) => {
   324→          URL.revokeObjectURL(img.src);
   325→          resolve(thumbBlob || blob);
   326→        },
   327→        'image/jpeg',
   328→        0.7
   329→      );
   330→    };
   331→
   332→    img.onerror = () => {
   333→      URL.revokeObjectURL(img.src);
   334→      resolve(blob);
   335→    };
   336→
   337→    img.src = URL.createObjectURL(blob);
   338→  });
   339→}
   340→
   341→// ============================================================================
   342→// TYPES EXPORT
   343→// ============================================================================
   344→
   345→export type MaterialMetadata = MaterialsDB['metadata']['value'];
   346→export type MaterialFile = MaterialsDB['files']['value'];
   347→
   348→// ============================================================================
   349→// UNIFIED MATERIAL RECORD (for Archive View)
   350→// Combines tool-based materials from API with file-based materials from IndexedDB
   351→// ============================================================================
   352→
   353→export interface MaterialRecord {
   354→  id: string;
   355→  toolId: string;
   356→  toolType: ToolType;
   357→  title?: string;
   358→  content: Record<string, unknown>;
   359→  maestroId?: string;
   360→  sessionId?: string;
   361→  subject?: string;
   362→  preview?: string;
   363→  status: 'active' | 'archived' | 'deleted';
   364→  // User interaction (Issue #37 - Archive features)
   365→  userRating?: number; // 1-5 stars
   366→  isBookmarked: boolean;
   367→  viewCount: number;
   368→  createdAt: Date;
   369→  updatedAt: Date;
   370→}
   371→
   372→/**
   373→ * Get all active materials (tools + files) for the Archive View
   374→ * Fetches from the /api/materials endpoint which queries Prisma
   375→ */
   376→export async function getActiveMaterials(): Promise<MaterialRecord[]> {
   377→  if (typeof window === 'undefined') {
   378→    return [];
   379→  }
   380→
   381→  try {
   382→    // Get userId from sessionStorage (temporary until auth is implemented)
   383→    const userId = sessionStorage.getItem('convergio-user-id') || 'default-user';
   384→
   385→    const response = await fetch(`/api/materials?userId=${userId}&status=active`);
   386→    if (!response.ok) {
   387→      logger.error('Failed to fetch materials', { status: response.status });
   388→      return [];
   389→    }
   390→
   391→    const data = await response.json();
   392→    return data.materials || [];
   393→  } catch (error) {
   394→    logger.error('Error fetching active materials', { error });
   395→    return [];
   396→  }
   397→}
   398→

